#include <bits/stdc++.h>
using namespace std;

int n, a[15], b[15];
int ans = 0, tmp = 0;
bool used[15];

void DFS(int x, int t) {
    if (x == n) {
        ans = min(ans, tmp + 1);
    }
    for (int i = 0; i < n; i++) {
        if (!used[i]) {
            used[i] = true;
            if (t == -1) {
                DFS(x + 1, i);
            }
            else {
                tmp += max(b[t], a[i]) + 1;
                DFS(x + 1, i);
                tmp -= max(b[t], a[i]) + 1;
            }
            used[i] = false;
        }
    }
}

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }
    for (int i = 0; i < n; i++) {
        cin >> b[i];
    }
    ans = INT_MAX;
    DFS(0, -1);
    cout << ans;
    return 0;
}
